             printf '%s' "property"
             ;;
@@ -70,6 +82,18 @@ suite_symbol() {
         ctype_local)
             printf '%s' "isalnum"
             ;;
+        math_trig_local)
+            printf '%s' "sin"
+            ;;
+        pthread_mutex_local)
+            printf '%s' "pthread_mutex_init"
+            ;;
+        stdio_buffer_local)
+            printf '%s' "setvbuf"
+            ;;
+        stdlib_conversion_local)
+            printf '%s' "strtol"
+            ;;
